import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    if not unvisited_customers:
        return None

    best_node = None
    min_score = float('inf')

    for i, cust_pos in enumerate(unvisited_customers):
        dist_to_cust = np.linalg.norm(cur_truck_pos - cust_pos)
        eta = current_time + (dist_to_cust / truck_speed)

        window_start, window_end = time_windows[i]

        if eta < window_start:
            score = window_start - eta
        elif eta > window_end:
            score = eta - window_end + 1000  # Penalty for missing time window
        else:
            score = 0

        score += dist_to_cust  # Add distance cost

        # Look-ahead heuristic: How close this customer is to the depot
        score += np.linalg.norm(cust_pos - depot_pos)

        # Adjust based on other trucks
        for truck_pos in all_truck_pos:
            if not np.array_equal(truck_pos, cur_truck_pos):
                dist_other = np.linalg.norm(truck_pos - cust_pos)
                if dist_other < dist_to_cust:
                    score += 500  # Penalty if another truck might reach it sooner

        if score < min_score:
            min_score = score
            best_node = i

    return best_node
